SELECT end_status AS endStatus, COUNT(*) AS businessCount, IFNULL(SUM(total_price), 0) AS totalPrice FROM crm_business WHERE deleted = 0 AND end_status IS NOT NULL
AND status_type_id = #{statusTypeId}
AND owner_user_id IN
#{userId}
AND create_time BETWEEN #{times[0],javaType=java.time.LocalDateTime} AND #{times[1],javaType=java.time.LocalDateTime} GROUP BY end_status

SELECT status.id AS statusId, status.name AS statusName, status.percent AS statusPercent, status.sort AS sort, COUNT(business.id) AS businessCount, IFNULL(SUM(business.total_price), 0) AS totalPrice FROM crm_business_status status LEFT JOIN crm_business business ON business.status_id = status.id AND business.deleted = 0 AND business.end_status IS NULL AND business.owner_user_id IN
#{userId}
AND business.create_time BETWEEN #{times[0],javaType=java.time.LocalDateTime} AND #{times[1],javaType=java.time.LocalDateTime} WHERE status.deleted = 0
AND status.type_id = #{statusTypeId}
GROUP BY status.id, status.name, status.percent, status.sort ORDER BY status.sort ASC

SELECT DATE_FORMAT(create_time, '%Y-%m-%d') AS time, COUNT(*) AS businessCreateCount, IFNULL(SUM(total_price), 0) AS totalPrice FROM crm_business WHERE deleted = 0
AND status_type_id = #{statusTypeId}
AND owner_user_id IN
#{userId}
AND create_time BETWEEN #{times[0],javaType=java.time.LocalDateTime} AND #{times[1],javaType=java.time.LocalDateTime} GROUP BY time

SELECT DATE_FORMAT(create_time, '%Y-%m-%d') AS time, COUNT(*) AS businessCount, SUM(IF(end_status = 1, 1, 0)) AS businessWinCount FROM crm_business WHERE deleted = 0
AND status_type_id = #{statusTypeId}
AND owner_user_id IN
#{userId}
AND create_time BETWEEN #{times[0],javaType=java.time.LocalDateTime} AND #{times[1],javaType=java.time.LocalDateTime} GROUP BY time
